SELECT vehicle_name, model, make, year, vin, registration_number, type, chassis_number, engine_number, fuel_type, transmission_type, horsepower, torque, last_maintenance_date, status
FROM vehicles
WHERE type = 'race car';

SELECT v.vehicle_name, v.model, m.maintenance_count
FROM vehicles v
INNER JOIN (
  SELECT vehicle_id, COUNT(*) AS maintenance_count
  FROM vehicle_maintenance
  GROUP BY vehicle_id
) m ON v.vehicle_id = m.vehicle_id
WHERE v.vehicle_id IN (
  SELECT vehicle_id FROM test_sessions WHERE track_id = 0
);

SELECT users.user_name, test_sessions.session_date
FROM users
JOIN test_sessions ON users.user_id = test_sessions.driver_id;

SELECT u.user_name, u.email, u.role, u.department, u.phone_number, u.last_login_date, u.status
FROM users u
JOIN data_versioning dv ON u.user_id = dv.versioned_by;

SELECT sensor_id, sensor_name, sensor_type
FROM vehicle_sensors
ORDER BY sensor_name ASC;

SELECT users.user_id, users.user_name, vehicle_sensors.sensor_type
FROM users, vehicle_sensors
WHERE users.role = 'data scientist' AND vehicle_sensors.sensor_type = 'brake';

SELECT session_type, session_date, COUNT(*) as number_of_sessions
FROM test_sessions
GROUP BY session_type, session_date;

SELECT model 
FROM vehicles 
WHERE status = 'active';
